// folderOf("docs/helix/01-frame/prd.md") => "docs/helix/01-frame"
// folderOf("README.md") => "/"
const FOLDER_RE = /^(.*)\/[^/]+$/;
export function folderOf(path: string): string {
	const m = path.match(FOLDER_RE);
	if (!m) return '/';
	return m[1] || '/';
}

// prefixOf("docs/helix/01-frame/prd.md") => "docs"
// prefixOf("/library/personas/x.md") => "library"
const PREFIX_RE = /^\/?([^/]+)/;
export function prefixOf(path: string): string {
	const m = path.match(PREFIX_RE);
	return m ? m[1] : '';
}

// Workflow stage derivation. Matches the canonical HELIX-style numbered
// stage segment (e.g. 01-frame, 02-design) anywhere in the path. Returns
// the bare stage name lowercased, or null when no stage segment is found.
const STAGE_RE = /(?:^|\/)\d{2}-([a-z][a-z0-9-]*)(?:\/|$)/i;
export function workflowStageOf(path: string): string | null {
	const m = path.match(STAGE_RE);
	return m ? m[1].toLowerCase() : null;
}

// Whether the workflow-stage axis should be shown for the given paths.
// The axis is hidden when no artifact in view has a derivable stage.
export function axisAvailable(paths: Iterable<string>): boolean {
	for (const p of paths) {
		if (workflowStageOf(p) !== null) return true;
	}
	return false;
}

export interface Groupable {
	path: string;
	mediaType: string;
}

// Generic, project-neutral label for the workflow-stage axis.
export const WORKFLOW_STAGE_LABEL = 'Workflow stage';

export const WORKFLOW_STAGE_FALLBACK_LABEL = 'Unstaged';

export function groupKey(item: Groupable, by: GroupBy): string {
	switch (by) {
		case 'folder':
			return folderOf(item.path);
		case 'prefix':
			return prefixOf(item.path);
		case 'mediaType':
			return item.mediaType || 'unknown';
		case 'workflowStage':
			return workflowStageOf(item.path) ?? WORKFLOW_STAGE_FALLBACK_LABEL;
	}
}

export function groupItems<T extends Groupable>(
	items: T[],
	by: GroupBy
): { key: string; items: T[] }[] {
	const buckets = new Map<string, T[]>();
	for (const it of items) {
		const k = groupKey(it, by);
		const arr = buckets.get(k);
		if (arr) arr.push(it);
		else buckets.set(k, [it]);
	}
	return Array.from(buckets.entries())
		.sort(([a], [b]) => a.localeCompare(b))
		.map(([key, items]) => ({ key, items }));
}

export const GROUP_BY_LABELS: Record<GroupBy, string> = {
	folder: 'Folder',
	prefix: 'Prefix',
	mediaType: 'Media type',
	workflowStage: WORKFLOW_STAGE_LABEL
};

export const GROUP_BY_OPTIONS: { value: GroupBy; label: string }[] = [
	{ value: 'folder', label: GROUP_BY_LABELS.folder },
	{ value: 'prefix', label: GROUP_BY_LABELS.prefix },
	{ value: 'mediaType', label: GROUP_BY_LABELS.mediaType },
	{ value: 'workflowStage', label: WORKFLOW_STAGE_LABEL }
];

export function groupCountLabel(
	groupCount: number,
	loadedCount: number,
	hasNextPage: boolean
): string {
	return hasNextPage ? `${groupCount} of ${loadedCount} loaded` : `${groupCount}`;
}

package registry

import (
	"fmt"
	"os"
	"path/filepath"
	"time"

	"gopkg.in/yaml.v3"
)

// InstalledEntry records an installed package.
type InstalledEntry struct {
	Name        string      `yaml:"name"`
	Version     string      `yaml:"version"`
	Type        PackageType `yaml:"type"`
	Source      string      `yaml:"source"`
	InstalledAt time.Time   `yaml:"installed_at"`
	Files       []string    `yaml:"files"`
}

// InstalledState is the top-level structure of installed.yaml.
type InstalledState struct {
	Installed []InstalledEntry `yaml:"installed"`
}

// installedStatePath returns the path to ~/.ddx/installed.yaml.
func installedStatePath() (string, error) {
	home, err := os.UserHomeDir()
	if err != nil {
		return "", fmt.Errorf("cannot determine home directory: %w", err)
	}
	return filepath.Join(home, ".ddx", "installed.yaml"), nil
}

// LoadState reads installed.yaml, returning an empty state if the file doesn't exist.
func LoadState() (*InstalledState, error) {
	path, err := installedStatePath()
	if err != nil {
		return nil, err
	}

	data, err := os.ReadFile(path)
	if os.IsNotExist(err) {
		return &InstalledState{}, nil
	}
	if err != nil {
		return nil, fmt.Errorf("reading installed state: %w", err)
	}

	var state InstalledState
	if err := yaml.Unmarshal(data, &state); err != nil {
		return nil, fmt.Errorf("parsing installed state: %w", err)
	}
	return &state, nil
}

// SaveState writes installed.yaml.
func SaveState(state *InstalledState) error {
	path, err := installedStatePath()
	if err != nil {
		return err
	}

	if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
		return fmt.Errorf("creating ~/.ddx directory: %w", err)
	}

	data, err := yaml.Marshal(state)
	if err != nil {
		return fmt.Errorf("marshaling installed state: %w", err)
	}

	if err := os.WriteFile(path, data, 0644); err != nil {
		return fmt.Errorf("writing installed state: %w", err)
	}
	return nil
}

// VerifyFiles checks whether any recorded files for the entry exist on disk.
// Returns true if at least one file exists, false if all are missing.
func (e *InstalledEntry) VerifyFiles() bool {
	if len(e.Files) == 0 {
		return false
	}
	for _, f := range e.Files {
		expanded := ExpandHome(f)
		if _, err := os.Stat(expanded); err == nil {
			return true
		}
		// Check if it's a symlink that resolves
		if info, err := os.Lstat(expanded); err == nil && info.Mode()&os.ModeSymlink != 0 {
			target, err := os.Readlink(expanded)
			if err == nil {
				if !filepath.IsAbs(target) {
					target = filepath.Join(filepath.Dir(expanded), target)
				}
				if _, err := os.Stat(target); err == nil {
					return true
				}
			}
		}
	}
	return false
}

// FindInstalled returns the entry for name, or nil if not installed.
func (s *InstalledState) FindInstalled(name string) *InstalledEntry {
	for i := range s.Installed {
		if s.Installed[i].Name == name {
			return &s.Installed[i]
		}
	}
	return nil
}

// AddOrUpdate adds a new entry or replaces an existing one.
func (s *InstalledState) AddOrUpdate(entry InstalledEntry) {
	for i := range s.Installed {
		if s.Installed[i].Name == entry.Name {
			s.Installed[i] = entry
			return
		}
	}
	s.Installed = append(s.Installed, entry)
}

// Remove removes an entry by name. Returns false if not found.
func (s *InstalledState) Remove(name string) bool {
	for i := range s.Installed {
		if s.Installed[i].Name == name {
			s.Installed = append(s.Installed[:i], s.Installed[i+1:]...)
			return true
		}
	}
	return false
}

