func TestArtifacts_ListAll(t *testing.T) {
	t.Setenv("HOME", t.TempDir())
	workDir, store := setupIntegrationDir(t)
	workDir = setupArtifactFixtureInDir(t, workDir)

	srv := httptest.NewServer(newArtifactGQLHandler(workDir, store))
	defer srv.Close()

