	artifacts := data["artifacts"].(map[string]interface{})
	total := int(artifacts["totalCount"].(float64))
	if total < 3 {
		t.Errorf("expected at least 3 artifacts (1 markdown + 2 sidecar), got %d", total)
	}

	edges := artifacts["edges"].([]interface{})
