+	cache.Store(input.IdempotencyKey, originatingBeadID)
+
+	persisted, err := store.Get(originatingBeadID)
+	if err != nil {
+		return nil, err
+	}
+	return &RunRequeueResult{
+		Bead:         beadModelFromBead(persisted),
+		Deduplicated: false,
+	}, nil
+}
