+	go func() {
+		defer unsub()
+		defer close(out)
+		for {
+			select {
+			case <-ctx.Done():
+				return
+			case evt, ok := <-src:
+				if !ok {
+					return
+				}
+				ts := evt.TS.Format(time.RFC3339)
+				we := &WorkerEvent{
+					EventID:   evt.EventID,
+					WorkerID:  evt.WorkerID,
+					Phase:     evt.Phase,
+					Timestamp: ts,
+				}
+				if evt.Message != "" {
+					we.LogLine = &evt.Message
+				}
+				if evt.BeadID != "" {
+					beadID := evt.BeadID
+					we.BeadID = &beadID
+				}
+				select {
+				case out <- we:
+				case <-ctx.Done():
+					return
+				}
+			}
+		}
+	}()
+
+	return out, nil
